from collections import deque


class _N:
    __slots__ = ("val", "left", "right")
    def __init__(self, v): self.val = v; self.left = None; self.right = None


def _build(vals):
    if not vals or vals[0] is None: return None
    root = _N(vals[0]); q = deque([root]); i = 1
    while q and i < len(vals):
        n = q.popleft()
        if i < len(vals):
            if vals[i] is not None: n.left = _N(vals[i]); q.append(n.left)
            i += 1
        if i < len(vals):
            if vals[i] is not None: n.right = _N(vals[i]); q.append(n.right)
            i += 1
    return root


def max_path_sum(root):
    r = _build(root)
    best = [float('-inf')]

    def gain(node):
        if node is None:
            return 0
        left_gain = max(gain(node.left), 0)
        right_gain = max(gain(node.right), 0)
        best[0] = max(best[0], node.val + left_gain + right_gain)
        return node.val + max(left_gain, right_gain)

    gain(r)
    return best[0]
